1750 void ConstraintInfo::addFactImpl(CmpInst::Predicate Pred, Value *A, Value *B,
1751                                  unsigned NumIn, unsigned NumOut,
1752                                  SmallVectorImpl<StackEntry> &DFSInStack,
1753                                  bool ForceSignedSystem) {
1754   // If the constraint has a pre-condition, skip the constraint if it does not
1755   // hold.
1756   SmallVector<Value *> NewVariables;
1757   auto R = getConstraint(Pred, A, B, NewVariables, ForceSignedSystem);
1758 
1759   // TODO: Support non-equality for facts as well.
1760   if (!R.isValid(*this) || R.isNe())
1761     return;
1762 
1763   LLVM_DEBUG(dbgs() << "Adding '"; dumpUnpackedICmp(dbgs(), Pred, A, B);
1764              dbgs() << "'\n");
1765   auto &CSToUse = getCS(R.IsSigned);
1766   if (R.Coefficients.empty())
1767     return;
1768 
1769   bool Added = CSToUse.addVariableRowFill(R.Coefficients);
1770   if (!Added)
1771     return;
1772 
1773   // If R has been added to the system, add the new variables and queue it for
1774   // removal once it goes out-of-scope.
1775   SmallVector<Value *, 2> ValuesToRelease;
1776   auto &Value2Index = getValue2Index(R.IsSigned);
1777   for (Value *V : NewVariables) {
1778     Value2Index.insert({V, Value2Index.size() + 1});
1779     ValuesToRelease.push_back(V);
1780   }
1781 
1782   LLVM_DEBUG({
1783     dbgs() << "  constraint: ";
1784     dumpConstraint(R.Coefficients, getValue2Index(R.IsSigned));
1785     dbgs() << "\n";
1786   });
1787 
1788   DFSInStack.emplace_back(NumIn, NumOut, R.IsSigned,
1789                           std::move(ValuesToRelease));
1790 
1791   if (!R.IsSigned) {
1792     for (Value *V : NewVariables) {
1793       ConstraintTy VarPos(SmallVector<int64_t, 8>(Value2Index.size() + 1, 0),
1794                           false, false, false);
