1845 static bool
1846 tryToSimplifyOverflowMath(IntrinsicInst *II, ConstraintInfo &Info,
1847                           SmallVectorImpl<Instruction *> &ToRemove) {
1848   auto DoesConditionHold = [](CmpInst::Predicate Pred, Value *A, Value *B,
1849                               ConstraintInfo &Info) {
1850     auto R = Info.getConstraintForSolving(Pred, A, B);
1851     if (R.size() < 2 || !R.isValid(Info))
1852       return false;
1853 
1854     auto &CSToUse = Info.getCS(R.IsSigned);
1855     return CSToUse.isConditionImplied(R.Coefficients);
1856   };
1857 
1858   bool Changed = false;
1859   if (II->getIntrinsicID() == Intrinsic::ssub_with_overflow) {
1860     // If A s>= B && B s>= 0, ssub.with.overflow(a, b) should not overflow and
1861     // can be simplified to a regular sub.
1862     Value *A = II->getArgOperand(0);
1863     Value *B = II->getArgOperand(1);
1864     if (!DoesConditionHold(CmpInst::ICMP_SGE, A, B, Info) ||
1865         !DoesConditionHold(CmpInst::ICMP_SGE, B,
1866                            ConstantInt::get(A->getType(), 0), Info))
1867       return false;
1868     Changed = replaceSubOverflowUses(II, A, B, ToRemove);
1869   }
1870   return Changed;
1871 }
