1896   // first. Assume facts and checks are ordered according to their relative
1897   // order in the containing basic block. Also make sure conditions with
1898   // constant operands come before conditions without constant operands. This
1899   // increases the effectiveness of the current signed <-> unsigned fact
1900   // transfer logic.
1901   stable_sort(S.WorkList, [](const FactOrCheck &A, const FactOrCheck &B) {
1902     auto HasNoConstOp = [](const FactOrCheck &B) {
1903       Value *V0 = B.isConditionFact() ? B.Cond.Op0 : B.Inst->getOperand(0);
1904       Value *V1 = B.isConditionFact() ? B.Cond.Op1 : B.Inst->getOperand(1);
1905       return !isa<ConstantInt>(V0) && !isa<ConstantInt>(V1);
1906     };
